import sys

class Solution:
    def maxNumber(self, nums: list[int]) -> int:
        n = len(nums)
        dp = [[0] * n for _ in range(n)]
        for i in range(n):
            dp[i][i] = 0
        for length in range(1, n):
            for i in range(n - length):
                j = i + length
                dp[i][j] = nums[i] * nums[j] + dp[i + 1][j - 1]
                for k in range(i + 1, j):
                    dp[i][j] = max(dp[i][j], nums[i] * nums[k] + nums[j] * dp[i][k - 1] + nums[k] * dp[k + 1][j])
        return dp[0][n - 1]

