#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int maxNumber(vector<int>& nums) {
        int n = nums.size();
        vector<vector<int>> dp(n, vector<int>(n));
        for (int i = 0; i < n; i++) {
            dp[i][i] = 0;
        }
        for (int length = 1; length < n; length++) {
            for (int i = 0; i < n - length; i++) {
                int j = i + length;
                dp[i][j] = nums[i] * nums[j] + dp[i + 1][j - 1];
                for (int k = i + 1; k < j; k++) {
                    dp[i][j] = max(dp[i][j], nums[i] * nums[k] + nums[j] * dp[i][k - 1] + nums[k] * dp[k + 1][j]);
                }
            }
        }
        return dp[0][n - 1];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.maxNumber(nums);
    cout << ans << "\n";
    return 0;
}
